div.div:
{% for r in site.data.resources -%}
  {%- assign key = r[0] -%}
  {%- assign res = r[1] -%}
  {%- if key contains "CodeSystem/" -%}
    {%- if res.content != "supplement" -%}


            {{res.title}}

    {%- endif -%}
  {%- endif -%}
{%- endfor -%}

{% for r in site.data.resources -%}
  {%- assign key = r[0] -%}
  {%- assign res = r[1] -%}
  {%- if key contains "CodeSystem/" -%}
    {%- if res.content == "supplement" -%}


            {{res.title}}

    {%- endif -%}
  {%- endif -%}
{%- endfor -%}
